import{_ as e,c as a,a1 as o,o as n}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Using ZAP (Zed Attack Proxy)","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/10-session-hijacking/1-Using-ZAP.md","filePath":"categories/ethical-hacking-labs/10-session-hijacking/1-Using-ZAP.md"}'),s={name:"categories/ethical-hacking-labs/10-session-hijacking/1-Using-ZAP.md"};function r(i,t,c,g,p,l){return n(),a("div",null,t[0]||(t[0]=[o('<h1 id="using-zap-zed-attack-proxy" tabindex="-1">Using ZAP (Zed Attack Proxy) <a class="header-anchor" href="#using-zap-zed-attack-proxy" aria-label="Permalink to &quot;Using ZAP (Zed Attack Proxy)&quot;">​</a></h1><p>Zed Attack Proxy (ZAP) is a free, open-source penetration testing tool being maintained under the umbrella of the Open Web Application Security Project (OWASP). ZAP is designed specifically for testing web applications and is both flexible and extensible.</p><p align="center"><img src="https://www.zaproxy.org/getting-started/images/browser-no-proxy.png"></p><p>At its core, ZAP is what is known as a “man-in-the-middle proxy.” It stands between the tester’s browser and the web application so that it can intercept and inspect messages sent between browser and web application, modify the contents if needed, and then forward those packets on to the destination. It can be used as a stand-alone application, and as a daemon process. <a href="https://www.zaproxy.org/getting-started/" target="_blank" rel="noreferrer">[...]</a></p><p><a href="https://www.zaproxy.org/download/" target="_blank" rel="noreferrer">&gt;&gt; ZAP Download</a></p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Intercept the Traffic between server and client</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Windows Server 2012 or 2016 virtual machine (Attacker)</li><li>Windows 10 virtual machine (Target)</li></ul><h2 id="setup-the-proxy" tabindex="-1">Setup the Proxy <a class="header-anchor" href="#setup-the-proxy" aria-label="Permalink to &quot;Setup the Proxy&quot;">​</a></h2><ol><li><p>Log into the <strong>Windows 10</strong> and launch any browser, in this lab: <strong>Firefox</strong>.</p></li><li><p>Go to <strong>Settings</strong> &gt; <strong>Network Settings</strong></p></li><li><p>On <strong>Proxy Settings</strong>, check the box <strong>Manual Proxy Configuration</strong>, and type the Attacker machine&#39;s IP address on port <strong>8080</strong> as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-0.png" alt="firefox-proxy"></p></li><li><p>You also can configure directly on <strong>Internet Properties</strong> on <strong>Control Panel</strong> &gt; <strong>Connections Tab</strong> &gt; <strong>LAN Settings</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-7.png" alt="proxy"><strong>Check the Proxy Server checkbox and type the attacker machine&#39;s IP address and port 8080</strong> as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-8.png" alt="proxy2"></p></li></ol><h2 id="setting-up-zap-zed-attack-proxy" tabindex="-1">Setting Up ZAP (Zed Attack Proxy) <a class="header-anchor" href="#setting-up-zap-zed-attack-proxy" aria-label="Permalink to &quot;Setting Up ZAP (Zed Attack Proxy)&quot;">​</a></h2><p>Switch to Attacker Machine (Windows Server).</p><p>Note: Make sure to install <strong>Java Run time</strong></p><ol><li><p>Download ZAP &gt; <a href="https://www.zaproxy.org/download/" target="_blank" rel="noreferrer">https://www.zaproxy.org/download/</a></p></li><li><p>On installatin process, make sure to select the option: <strong>&quot;No, I do not want to persist this session at this moment in time&quot;</strong>: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-1.png" alt="zap1"></p></li><li><p>On the OWASP ZAP main window, click on the <strong>&quot;+&quot;</strong> icon in the right pane, then add the <strong>Break</strong> tab, as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-2.png" alt="zap-main-window"> The <strong>Break</strong> tab allows you to <strong>modify a response</strong> or <strong>request</strong> when it has been caught by the ZAP. It also allows you to modify some elements that you cannot modify through your browser; these include: <strong>The Header, Hidden fields, Disabled fields, Fields that use Javascript to filter out illegal characters</strong>.</p></li><li><p>Once the <strong>Break tab</strong> is added, you need to configure the ZAP to work as a proxy, go to <strong>Options</strong> by click on <strong>gear icon</strong> on the top, as show below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-3.png" alt="zap-options"></p></li><li><p>On the <strong>Options</strong> window, select the <strong>Local Proxies</strong> from the left pane; The address is the <strong>Windows Server IP address</strong> and port is <strong>8080</strong> by default: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-4.png" alt="zap-options-2"></p></li><li><p>Go back to <strong>ZAP main window</strong> and click on <strong>Green Button (Set break on all requests and responses)</strong> as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-5.png" alt="zap-green-icon"> This button sets and unsets a global break point that will trap and display the next response or request in Break tab from the Target&#39;s machine. You can modify any part of the request or response that you want and send it to the victim&#39;s application by clicking either <strong>Step</strong> or <strong>Continue</strong>. Alternatively, you can click <strong>Drop</strong> to dispose of the request or response.</p></li></ol><hr><ol><li><p><strong>Switch back to the target machine(Windows 10)</strong> and launch the same browser in which you have configured the proxy settings.</p></li><li><p>Type the URL: www.certifiedhacker.com , in case you got any warning messages just accept the risk and continue.</p></li><li><p>Now, <strong>switch to the attacker machine(Windows Server)</strong>, you will notice that the ZAP proxy is started capturing the requests of the target. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-6.png" alt="zap6"></p></li><li><p>Now click the button <strong>&#39;submit and step to the next request&#39;</strong> until you capture the <strong>GET</strong> request of the browsed website. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-9.png" alt="zap7"></p></li></ol><p>You can modify all GET requests captured on the <strong>Break tab</strong> and forward the traffic to the target machine, changing the website and so on.</p>',18)]))}const u=e(s,[["render",r]]);export{d as __pageData,u as default};
